function Pill({ children, bg, color }) {
  return <span style={{ background: bg, color, borderRadius: 20, padding: "3px 11px", fontSize: 11, fontWeight: 700, letterSpacing: 0.2, whiteSpace: "nowrap" }}>{children}</span>;
}

function StockDot({ qty, threshold }) {
  const out = qty <= 0, low = qty <= threshold;
  const c = out ? W.red : low ? W.amber : W.green;
  const label = out ? "Out" : low ? "Low" : "In stock";
  return (
    <span style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 12, color: c, fontWeight: 600 }}>
      <span style={{ width: 8, height: 8, borderRadius: "50%", background: c, display: "inline-block" }} />
      {label}
    </span>
  );
}

